2632: void PresShell::FrameNeedsReflow(nsIFrame* aFrame,
2633:                                  IntrinsicDirty aIntrinsicDirty,
2634:                                  nsFrameState aBitToAdd,
2635:                                  ReflowRootHandling aRootHandling) {
2636:   MOZ_ASSERT(aBitToAdd == NS_FRAME_IS_DIRTY ||
2637:                  aBitToAdd == NS_FRAME_HAS_DIRTY_CHILDREN || !aBitToAdd,
2638:              "Unexpected bits being added");
2639: 
2640:   // FIXME bug 478135
2641:   NS_ASSERTION(
2642:       aIntrinsicDirty != IntrinsicDirty::FrameAncestorsAndDescendants ||
2643:           aBitToAdd != NS_FRAME_HAS_DIRTY_CHILDREN,
2644:       "bits don't correspond to style change reason");
2645: 
2646:   // FIXME bug 457400
2647:   NS_ASSERTION(!mIsReflowing, "can't mark frame dirty during reflow");
2648: 
2649:   // If we've not yet done the initial reflow, then don't bother
2650:   // enqueuing a reflow command yet.
2651:   if (!mDidInitialize) {
2652:     return;
2653:   }
2654: 
2655:   // If we're already destroying, don't bother with this either.
2656:   if (mIsDestroying) {
2657:     return;
2658:   }
2659: 
2660:   AutoTArray<nsIFrame*, 4> subtrees;
2661:   subtrees.AppendElement(aFrame);
2662: 
2663:   do {
2664:     nsIFrame* subtreeRoot = subtrees.PopLastElement();
2665: 
2666:     // Grab |wasDirty| now so we can go ahead and update the bits on
2667:     // subtreeRoot.
2668:     bool wasDirty = subtreeRoot->IsSubtreeDirty();
2669:     subtreeRoot->AddStateBits(aBitToAdd);
2670: 
2671:     // Determine whether we need to keep looking for the next ancestor
2672:     // reflow root if subtreeRoot itself is a reflow root.
2673:     bool targetNeedsReflowFromParent;
2674:     switch (aRootHandling) {
2675:       case ReflowRootHandling::PositionOrSizeChange:
2676:         targetNeedsReflowFromParent = true;
2677:         break;
2678:       case ReflowRootHandling::NoPositionOrSizeChange:
2679:         targetNeedsReflowFromParent = false;
2680:         break;
